bash_functions:
#!/bin/bash
set -euo pipefail

# Function with error handling
log() {
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] $*"
}

die() {
    log "ERROR: $*" >&2
    exit 1
}

check_deps() {
    local deps=("$@")
    for dep in "${deps[@]}"; do
        command -v "$dep" >/dev/null 2>&1 || die "Missing: $dep"
    done
}

log "Starting..."
check_deps curl jq
log "All dependencies found"

bash_error_handling:
#!/bin/bash
set -euo pipefail
trap 'echo "ERROR on line $LINENO. Exit code: $?" >&2' ERR
trap 'cleanup' EXIT

cleanup() {
    echo "Cleaning up..."
    rm -f "$TMPFILE" 2>/dev/null || true
}

TMPFILE=$(mktemp)
echo "Working in: $TMPFILE"

bash_input_validation:
#!/bin/bash
set -euo pipefail

usage() {
    echo "Usage: $0 <input_file> <output_file>"
    exit 1
}

[ $# -ge 2 ] || usage

INPUT="$1"
OUTPUT="$2"

[ -f "$INPUT" ] || { echo "Input not found: $INPUT" >&2; exit 1; }
[ -d "$(dirname "$OUTPUT")" ] || { echo "Output dir missing" >&2; exit 1; }

bash_sort_unique:
#!/bin/bash
set -euo pipefail

cat "{path}" | sort | uniq -c | sort -rn | head -20

bash_getopts:
#!/bin/bash
set -euo pipefail

VERBOSE=0
OUTPUT=""
INPUT=""

usage() {
    echo "Usage: $0 [-v] [-o output] -i input"
    exit 1
}

while getopts "vo:i:h" opt; do
    case $opt in
        v) VERBOSE=1 ;;
        o) OUTPUT="$OPTARG" ;;
        i) INPUT="$OPTARG" ;;
        h) usage ;;
        *) usage ;;
    esac
done

[ -n "$INPUT" ] || usage
[ $VERBOSE -eq 1 ] && echo "Input: $INPUT, Output: $OUTPUT"
